/**
 * Single source of truth for the `test/testing-types.ts` file written into
 * every game project by both `dreamboard new` and `dreamboard test`.
 */
export const TESTING_TYPES_CONTENT = `\
// Generated by dreamboard — do not edit by hand.
// Provides type exports and the defineScenario runtime helper for scenario files.
import type {
  CardId,
  DeckId,
  CardIdsByDeckId,
  CardIdsByHandId,
  GlobalState,
  HandId,
  PlayerId,
  PlayerState,
  StateName,
  GameActionParameter,
  ActionName,
} from "../shared/manifest";
import type { GameMessage, GameMessageType } from "../shared/game-message";

export interface ScenarioCardInfo {
  cardType: string;
  cardSetId: string;
  cardName?: string;
  description?: string;
  /** JSON-encoded card properties */
  properties: string;
}

export interface ScenarioGameState {
  currentPlayerIds: PlayerId[];
  currentState: StateName;
  decks: CardIdsByDeckId;
  /** playerId → handId → cardIds (all controlled players\\u2019 hands) */
  hands: Record<PlayerId, CardIdsByHandId>;
  /** handId → playerId → cardIds (visible to all players) */
  publicHands: Record<HandId, Record<PlayerId, CardId[]>>;
  cards: Record<CardId, ScenarioCardInfo>;
  /** Parsed global game variables */
  globalVariables: GlobalState;
  /** Parsed per-player variables keyed by player ID */
  playerVariables: Record<PlayerId, PlayerState>;
  isMyTurn: boolean;
}

export interface EventInspector {
  /** Count events of a given type */
  count(type: GameMessageType): number;
  /** Get the last event of a given type, or undefined */
  last<T extends GameMessageType>(type: T): Extract<GameMessage, { type: T }> | undefined;
  /** Get all events of a given type */
  all<T extends GameMessageType>(type: T): Array<Extract<GameMessage, { type: T }>>;
}

export type ExpectFn = (actual: unknown) => {
  toBe(expected: unknown): void;
  toEqual(expected: unknown): void;
  toBeDefined(): void;
  toBeUndefined(): void;
  toContain(expected: unknown): void;
  toBeGreaterThanOrEqual(expected: number): void;
};

export interface AssertContext {
  gameState: ScenarioGameState;
  events: EventInspector;
  expect: ExpectFn;
}

export type ScenarioStep = {
  [K in ActionName]: {
    playerId: PlayerId;
    actionType: K;
    parameters: GameActionParameter[K]["parameters"];
  };
}[ActionName];

export interface ScenarioDefinition {
  meta: { id: string; description: string };
  given: { base: string };
  when: { steps: ScenarioStep[] };
  then: { assert: (ctx: AssertContext) => void | Promise<void> };
}

export type NormalizedHands = Record<PlayerId, Partial<Record<HandId, CardId[]>>>;
export type NormalizedDecks = Partial<Record<DeckId, CardId[]>>;

function sortCardIds(cardIds: readonly CardId[]): CardId[] {
  return [...cardIds].sort();
}

export function getNormalizedHands(gameState: ScenarioGameState): NormalizedHands {
  const normalized: Partial<
    Record<PlayerId, Partial<Record<HandId, CardId[]>>>
  > = {};

  for (const [playerId, handsById] of Object.entries(gameState.hands) as Array<
    [PlayerId, CardIdsByHandId]
  >) {
    const playerHands: Partial<Record<HandId, CardId[]>> = {};
    for (const [handId, cardIds] of Object.entries(handsById) as Array<
      [HandId, CardId[]]
    >) {
      playerHands[handId] = sortCardIds(cardIds);
    }
    normalized[playerId] = playerHands;
  }

  return normalized as NormalizedHands;
}

export function getNormalizedDecks(gameState: ScenarioGameState): NormalizedDecks {
  const normalized: Partial<Record<DeckId, CardId[]>> = {};

  for (const [deckId, cardIds] of Object.entries(gameState.decks) as Array<
    [DeckId, CardId[]]
  >) {
    normalized[deckId] = sortCardIds(cardIds);
  }

  return normalized;
}

export function defineScenario(scenario: ScenarioDefinition): ScenarioDefinition {
  return scenario;
}
`;
